window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2012>1>a>i","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"i","group":"","topic":"FRUITS","question":"Study carefully specimens A and B and use them to answer questions 1(a) to 1(c).    Name the types of fruit in specimens A and B with reasons.","images":[],"marking_scheme":"Types of fruits: Garden Egg/A-Berry. Reason: It has a fleshy pericarp with many seeds embedded in it. Tridax B-Cypsela. Reason: Fruit bears a hairy calyx/hairy pappus/parachute. Dry single seeded fruit.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>1>a>ii","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"ii","group":"","topic":"FRUITS","question":"Study carefully specimens A and B and use them to answer questions 1(a) to 1(c).  Make a drawing, 8-10cm long of the lateral view of specimen B and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of the lateral view of specimen B/Tridax fruit","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>1>b","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"b","group":"","topic":"FRUITS","question":"Study carefully specimens A and B and use them to answer questions 1(a) to 1(c).  Describe the modes of dispersal of specimens A and B.","images":[],"marking_scheme":"Modes of dispersal of specimens A is by animal  The soft and edible fruit is eaten by man and animals while the seed is spat out; scattered or egested through the alimentary canal.    Modes of dispersal of specimens B is by wind.  The fruit is light in weight and the feathery pappus traps the air to be blown and dispersed by wind.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>1>c","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"c","group":"","topic":"FRUITS","question":"Study carefully specimens A and B and use them to answer questions 1(a) to 1(c).  In a tabular form, state five differences between specimens A and B.","images":[],"marking_scheme":"Specimen A (Garden Egg)Specimen B (Tridax frut)Fleshy pericarpDry pericarpSmooth epicarp/fruit wallHairy epicarpNo pappusPappus presentCalyx beneath fruitCalyx (pappus) on top of fruitCalyx presentCalyx modified into pappusLarge fruitSmall fruitHeavy fruitLight (in weight) fruitGreen/white/yellow in colourBrown in colour","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>2>a>i","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Study carefully specimens C, D and E and use them to answer questions 2(a) to 2(c).    State the mode of nutrition of specimen D.","images":[],"marking_scheme":"Mode of nutrition of Specimen D- Parasitic","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2012>2>a>ii","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"ii","group":"","topic":"PESTS","question":"Study carefully specimens C, D and E and use them to answer questions 2(a) to 2(c).  State one way by which each of specimens C, D and E is of economic importance.","images":[],"marking_scheme":"Specimen C/Grain Weevil: They destroy grains/reduce their food quality.  -Increase production cost for farmers thereby lowering the farmers income.    Specimen D/Tick: They infest cattle/dogs/suck their blood thereby making them anaemic; and reduce meat quality.  -They transmit diseases.   -They decrease resistance to diseases in cattle/dog.    Specimen E/Rat: They destroy stored food items/contamination of food.   -They spread diseases.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>2>b>i","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study carefully specimens C, D and E and use them to answer questions 2(a) to 2(c).  Classify specimens C, D and E into their phyla and classes.","images":[],"marking_scheme":"SpecimenPhylumClassCArthropodaInsectaDArthropodaArachnidaEChordataMammalia","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>2>b>ii","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study carefully specimens C, D and E and use them to answer questions 2(a) to 2(c).  List three observable characteristic features of each of the classes to which specimens C, D and E belong.","images":[],"marking_scheme":"Observable characteristics: Class Insecta/ Specimen C:   -Three body divisions/head, thorax and abdomen.   -Presence of 6 jointed/'3 pairs of jointed walking legs;   -presence of compound eyes.  -Presence of segmented thorax/prothorax, mesothorax and metathorax.  -Presence of wings.   -Presence of body divisions/Cephalothorax and abdomen.  -It has a pair of antennae    Specimen D(Class Arachnida)  -It has 4 pairs of legs  -It has two body divisions of cephalothorax and abdomen  -Presence of simple eyes/ocelli   -Presence of two appendages for feeding/peclipalps and chelicera.    Class Mammalia/specimen E :  Presence of hair/fur on body. Presence of external ears/pinnae. Presence of mammary glands.   The presence of four limbs for locomotion.  -Heterodont dentition.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>2>b>iii","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study carefully specimens C, D and E and use them to answer questions 2(a) to 2(c).  In a tabular form, state two observable differences between C and D.","images":[],"marking_scheme":"C/Grain WeevilD/TickThree body division/head/ thorax and abdomenTwo body divisions/cephalothorax and abdomen3 pairs of legs/6 legs4 pairs of legs/8 legsCompound eyesSimple eye presentPresence of wingsAbsence of wingsDistinct thorax / thorax presentThorax fused with head/cephalothoraxPresence of antennaeAbsence of antennae","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>2>c","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"List four observable features of specimen E that are sensory in nature.","images":[],"marking_scheme":"(i) external ears/pinnae (ii) Skin/fur (iii) Whiskers (iv) Eyes (v) Nostrils (vi) Tail","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>3>a","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study carefully specimens J, K and L and use them to answer questions 4(a) to 4(d).    State the class of each of specimens J, K and L. State three reasons each for placing each of specimens J, K and L in their classes.","images":[],"marking_scheme":"Class of Specimen J-Tilapia: Osteichthyes.    Reason: Body is covered with scales. (ii) Presence of paired fins. (iii) Presence of lateral line(s). (iv) Presence of operculum/gill cover.    class of Specimen K/Toad: Amphibia     Reason: (i) Presence or warty skin. (ii) Presence of webbed digits. (iii) Presence of moist skin. (iv) Presence of bulging eyes. (v) Presence of ear drum.    Class of specimen L(Lizard) is Reptilia  -It has dry horny scales on the skin  -It has fore and hind limbs with clawed digits  -It has heterodont dentitition  -It has well developed retractable tongue","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>3>b","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"b","group":"","topic":"EVOLUTION : STRUCTURAL ADAPTATION","question":"Study carefully specimens J, K and L and use them to answer questions 4(a) to 4(d).  State two structural adaptations possessed by each of specimens K and L for escaping predators.","images":[],"marking_scheme":"Structural adaptations for escaping predation: Specimen K/Toad:  -Presence of poison gland on skin which secretes a substance which irritates/repels the predators.  -Counter shading of the dorsal and ventral sides/camouflage facilitate escape from predator.    (ii)Long hind limb and short muscular forelimb for jumping away and escaping from predator.    Structural adaptation of Specimen L/Lizard:  -Detachable tail to escape from predators.   -Skin colour blends with surrounding/camouflage to enhance escape from predators. (iii) Eyes for seeing and escaping predators. (iv) Limbs for running away from predators.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>3>c","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"c","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study carefully specimens J, K and L and use them to answer questions 4(a) to 4(d).  Make a drawing, 8 - 10cm long of the lateral view of specimen J.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of specimen J/Tilapia","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>3>d>i","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study carefully specimens J, K and L and use them to answer questions 4(a) to 4(d).  State: (i) two similarities between specimens J and L.","images":[],"marking_scheme":"Similarities between Specimen J& L: (i) Presence of eyes. (i) Presence of nostrils. (ii) Presence of Scales. (v) Presence of head. (v) Presence of tail.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2012>3>d>ii","subject":"Biology Practical","year":"2012","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study carefully specimens J, K and L and use them to answer questions 4(a) to 4(d).  State two observable differences between specimens J and L.","images":[],"marking_scheme":"J/TilapiaL/LizardPresence of finsPresence of limbsAbsence of tympanumPresence of tympanumLateral line presentLateral line absentShort tailLong tailPresence of operculum/gill coverNo operculum/gill cover","marks":"1","difficulty":"2"}];